"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["7885"],{6174(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"hello-world","metadata":{"permalink":"/commons-ts/blog/hello-world","editUrl":"https://github.com/open-kerno/commons-ts/tree/main/website/blog/2026-07-04-hello-world.mdx","source":"@site/blog/2026-07-04-hello-world.mdx","title":"Welcome to Open Kerno Commons","description":"We are happy to introduce @open-kerno/commons \u2014 a shared TypeScript utility library for Node.js services.","date":"2026-07-04T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/commons-ts/blog/tags/release"},{"inline":true,"label":"typescript","permalink":"/commons-ts/blog/tags/typescript"},{"inline":true,"label":"nodejs","permalink":"/commons-ts/blog/tags/nodejs"}],"readingTime":0.77,"hasTruncateMarker":true,"authors":[{"name":"Open Kerno Team","title":"Maintainers","url":"https://github.com/open-kerno","image_url":"https://avatars.githubusercontent.com/u/299951247?s=400&v=4","imageURL":"https://avatars.githubusercontent.com/u/299951247?s=400&v=4","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"hello-world","title":"Welcome to Open Kerno Commons","authors":{"name":"Open Kerno Team","title":"Maintainers","url":"https://github.com/open-kerno","image_url":"https://avatars.githubusercontent.com/u/299951247?s=400&v=4","imageURL":"https://avatars.githubusercontent.com/u/299951247?s=400&v=4"},"tags":["release","typescript","nodejs"],"date":"2026-07-04T00:00:00.000Z"},"unlisted":false},"content":"We are happy to introduce `@open-kerno/commons` \u2014 a shared TypeScript utility library for Node.js services.\\n\\n{/* truncate */}\\n\\n## What is it?\\n\\n`@open-kerno/commons` is a collection of well-tested, typed modules designed to solve common problems across backend services. Instead of copying the same utilities from project to project, you can install this package and start using them right away.\\n\\n## What is included?\\n\\n- **HTTP** \u2014 `HttpStatusCode` and `HttpMethod` enums covering all standard codes and methods.\\n- **Errors** \u2014 Typed error classes (`ServerError`, `BadRequestError`, `InternalServerError`, `DatabaseConnectionError`) with HTTP status codes and optional error payloads.\\n- **Collections** \u2014 `createMapFromArray` and `createSetFromArray` for fast lookups.\\n- **Math** \u2014 `prorate` for proportional distribution and `roundWithPrecision` for accurate rounding.\\n- **Logger** \u2014 A structured logger with field masking, built on Winston.\\n- **Infrastructure** \u2014 A PostgreSQL connection pool wrapper with session and transaction helpers.\\n- **Object** \u2014 `encodeJSON` for safe JSON parsing with typed fallbacks.\\n\\n## Getting started\\n\\n```bash\\nnpm install @open-kerno/commons\\n```\\n\\nCheck the [documentation](/docs) for the full API reference."}]}}')}}]);